import type { Locale } from './i18n'
import type { PartId } from './data'

export type LocalText = { zh: string; en: string }
export type LabKind = 'wing' | 'floor' | 'impact' | 'structure' | 'protection' | 'tire' | 'brake' | 'suspension' | 'steering' | 'battery' | 'inverter' | 'motor' | 'differential' | 'cooling' | 'control' | 'telemetry'

export type FormulaCard = {
  name: LocalText
  expression: string
  latex: string
  variables: LocalText
  insight: LocalText
}

export type GuidedExperiment = {
  title: LocalText
  question: LocalText
  steps: LocalText[]
  evidence: LocalText
}

export type DiagnosticCase = {
  title: LocalText
  symptom: LocalText
  checks: LocalText[]
  resolution: LocalText
}

export type EngineeringLesson = {
  labKind: LabKind
  overview: LocalText
  subcomponents: [LocalText, LocalText, LocalText, LocalText, LocalText, LocalText]
  concepts: [LocalText, LocalText, LocalText]
  formulas: [FormulaCard, FormulaCard, FormulaCard]
  experiments: [GuidedExperiment, GuidedExperiment]
  decisions: [LocalText, LocalText, LocalText]
  validation: [LocalText, LocalText]
  diagnostics: [DiagnosticCase, DiagnosticCase]
  references: { title: string; url: string }[]
}

export const t = (value: LocalText, locale: Locale) => value[locale]
export const localise = t
const l = (zh: string, en: string): LocalText => ({ zh, en })
