const f = (nameZh: string, nameEn: string, expression: string, variablesZh: string, variablesEn: string, insightZh: string, insightEn: string): FormulaCard => {
  const latex = FORMULA_LATEX[expression]
  if (!latex) throw new Error(`Missing LaTeX mapping for formula: ${expression}`)
  return { name: l(nameZh, nameEn), expression, latex, variables: l(variablesZh, variablesEn), insight: l(insightZh, insightEn) }
}
const e = (titleZh: string, titleEn: string, questionZh: string, questionEn: string, steps: [string, string][], evidenceZh: string, evidenceEn: string): GuidedExperiment => ({
  title: l(titleZh, titleEn), question: l(questionZh, questionEn), steps: steps.map(([zh, en]) => l(zh, en)), evidence: l(evidenceZh, evidenceEn),
})
const d = (titleZh: string, titleEn: string, symptomZh: string, symptomEn: string, checks: [string, string][], resolutionZh: string, resolutionEn: string): DiagnosticCase => ({
  title: l(titleZh, titleEn), symptom: l(symptomZh, symptomEn), checks: checks.map(([zh, en]) => l(zh, en)), resolution: l(resolutionZh, resolutionEn),
})

